import { readFile, writeFile } from "node:fs/promises";
import { createBucket, put, list } from "@tigrisdata/storage";

async function main() {
  const rawTrialId = (await readFile("/logs/artifacts/trial_id", "utf-8")).trim();
  const trialId = rawTrialId.toLowerCase().replace(/[^a-z0-9.-]/g, "-");
  const bucketName = `harbor-tssdk-${trialId}`;

  console.log(`Using bucket: ${bucketName}`);

  const createResult = await createBucket(bucketName);
  if (createResult.error) {
    const msg = String(createResult.error?.message ?? createResult.error);
    const code = (createResult.error as any)?.name ?? "";
    const alreadyExists =
      /BucketAlreadyOwnedByYou|BucketAlreadyExists|already exists|already owned/i.test(
        msg + " " + code,
      );
    if (!alreadyExists) {
      console.error("createBucket failed:", createResult.error);
      process.exit(1);
    } else {
      console.log("Bucket already exists, continuing.");
    }
  } else {
    console.log("Bucket created.");
  }

  const objects = [
    { key: "inbox/msg-1.json", body: JSON.stringify({ id: 1 }) },
    { key: "inbox/msg-2.json", body: JSON.stringify({ id: 2 }) },
    { key: "inbox/msg-3.json", body: JSON.stringify({ id: 3 }) },
  ];

  for (const obj of objects) {
    const putResult = await put(obj.key, obj.body, {
      contentType: "application/json",
      allowOverwrite: true,
      config: { bucket: bucketName },
    });
    if (putResult.error) {
      console.error(`put ${obj.key} failed:`, putResult.error);
      process.exit(1);
    }
    console.log(`Uploaded ${obj.key}`);
  }

  const listResult = await list({
    prefix: "inbox/",
    config: { bucket: bucketName },
  });
  if (listResult.error || !listResult.data) {
    console.error("list failed:", listResult.error);
    process.exit(1);
  }

  const names = listResult.data.items.map((i) => i.name);
  await writeFile("/home/user/tigris-task/listing.txt", names.join("\n"));
  console.log("Listing written:", names);
}

main().catch((err) => {
  console.error("Unhandled error:", err);
  process.exit(1);
});
